using System; using Microsoft.Data.Sqlite; class Program { static void Main() { try { using var connection = new SqliteConnection("Data Source=C:\\EduSyncAI\\Data\\edusync.db"); connection.Open(); using var cmd = connection.CreateCommand(); cmd.CommandText = "SELECT Id FROM Students LIMIT 1"; var sId = cmd.ExecuteScalar(); cmd.CommandText = "SELECT Id FROM ClassSessions LIMIT 1"; var sessId = cmd.ExecuteScalar(); if (sId != null && sessId != null) { cmd.CommandText = "INSERT INTO Attendance (SessionId, StudentId, CheckInTime, CheckInMethod) VALUES (@sessId, @sId, @time, @method)"; cmd.Parameters.AddWithValue("@sessId", sessId); cmd.Parameters.AddWithValue("@sId", sId); cmd.Parameters.AddWithValue("@time", DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss")); cmd.Parameters.AddWithValue("@method", "Facial"); cmd.ExecuteNonQuery(); Console.WriteLine($"Inserted test record for Student {sId} in Session {sessId}"); } else { Console.WriteLine("Missing students or sessions to seed."); } } catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); } } }
